var client = null;
function getClient(queryTimeout) {
  if (!client) {
    const tokens = loadTokens();
    client = new NotebookLMClient(tokens, queryTimeout);
  }
  return client;
}
function createServer(queryTimeout) {
  const server = new McpServer({
    name: "notebooklm",
    version: "0.1.0"
  });
  registerTools(server, [
    ...notebookTools,
    ...sourceTools,
    ...studioTools,
    ...authTools,
    ...queryTools,
    ...researchTools
  ], getClient, {
    queryTimeout,
    onClientReset: () => {
      client = null;
    }
  });
  return server;
}

